export const getDeadlineColor = (deadline) => {
  const now = new Date();
  const diff = new Date(deadline) - now;
  const hoursLeft = diff / (1000 * 60 * 60);

  if (diff < 0) {
    return { bg: 'bg-red-100', text: 'text-red-800', label: 'Overdue' };
  } else if (hoursLeft <= 2) {
    return { bg: 'bg-yellow-100', text: 'text-yellow-800', label: 'Urgent' };
  } else {
    return { bg: 'bg-green-100', text: 'text-green-800', label: 'On Track' };
  }
};

export const formatDate = (date) => {
  return new Date(date).toLocaleDateString('en-IN', {
    day: '2-digit',
    month: 'short',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  });
};

export const formatDateShort = (date) => {
  return new Date(date).toLocaleDateString('en-IN', {
    day: '2-digit',
    month: 'short',
    hour: '2-digit',
    minute: '2-digit',
  });
};
